import pandas as pd
from datetime import datetime, timedelta

class AccountingReport:
    def __init__(self, data_source):
        self.data_source = data_source
        self.data = self.load_data()

    def load_data(self):
        # Simulate loading data from an accounting system like QuickBooks or Sage
        # In a real scenario, this would involve connecting to an API or database
        return pd.read_csv(self.data_source)

    def generate_report(self, start_date, end_date):
        report_data = self.data[(self.data['date'] >= start_date) & (self.data['date'] <= end_date)]
        total_sales = report_data['sales'].sum()
        total_expenses = report_data['expenses'].sum()
        net_profit = total_sales - total_expenses

        report = {
            'Total Sales': total_sales,
            'Total Expenses': total_expenses,
            'Net Profit': net_profit,
            'Period Start': start_date,
            'Period End': end_date
        }
        return report

    def customize_period(self, period_type):
        today = datetime.today()
        if period_type == 'month':
            start_date = today.replace(day=1).date()
            end_date = (start_date + timedelta(days=31)).replace(day=1) - timedelta(days=1)
        elif period_type == 'quarter':
            start_date = (today - pd.offsets.QuarterBegin()).date()
            end_date = (start_date + pd.offsets.QuarterEnd()).date()
        elif period_type == 'year':
            start_date = today.replace(month=1, day=1).date()
            end_date = today.replace(month=12, day=31).date()
        else:
            raise ValueError("Invalid period type. Choose 'month', 'quarter', or 'year'.")

        return start_date, end_date

if __name__ == "__main__":
    data_source = 'accounting_data.csv'  # Path to the CSV file containing accounting data
    report_generator = AccountingReport(data_source)

    period_type = input("Enter the period type (month, quarter, year): ")
    start_date, end_date = report_generator.customize_period(period_type)
    report = report_generator.generate_report(start_date, end_date)

    print("Accounting Report:")
    for key, value in report.items():
        print(f"{key}: {value}")

