            'net_profit': filtered_data['income'].sum() - filtered_data['expenses'].sum(),
            'transactions_count': filtered_data.shape[0]
        }
        return report

    def get_date_range(self, period):
        end_date = datetime.now()
        if period == 'month':
            start_date = end_date - timedelta(days=30)
