        # Logic to generate a monthly report
        monthly_report = {}
        for entry in self.report_data:
            month = entry['date'].strftime('%Y-%m')
            if month not in monthly_report:
                monthly_report[month] = {'revenue': 0, 'expenses': 0}
            monthly_report[month]['revenue'] += entry['revenue']
            monthly_report[month]['expenses'] += entry['expenses']
        return monthly_report

