            year = entry['date'].year
            key = f"{year}-Q{quarter}"
            if key not in quarterly_report:
                quarterly_report[key] = {'revenue': 0, 'expenses': 0}
            quarterly_report[key]['revenue'] += entry['revenue']
            quarterly_report[key]['expenses'] += entry['expenses']
