            category = t['category']
            amount = t['amount']
            if category not in summary:
                summary[category] = {'income': 0, 'expense': 0}
            if t['transaction_type'] == 'income':
                summary[category]['income'] += amount
            elif t['transaction_type'] == 'expense':
