class AccountStatement:
    def __init__(self, data_source):
        self.data_source = data_source
        self.statements = []

    def fetch_data(self, start_date, end_date):
        # Simulate fetching data from the data source
        # In a real implementation, this would connect to QuickBooks or Sage
        self.statements = self.data_source.get_statements(start_date, end_date)

    def generate_report(self, period):
        report = {}
        for statement in self.statements:
            date = statement['date']
            if self._is_in_period(date, period):
                category = statement['category']
                amount = statement['amount']
                if category not in report:
                    report[category] = 0
                report[category] += amount
        return report

    def _is_in_period(self, date, period):
        if period == 'month':
            return date.month == self.current_month() and date.year == self.current_year()
        elif period == 'quarter':
            return (date.month - 1) // 3 == (self.current_month() - 1) // 3 and date.year == self.current_year()
        elif period == 'year':
            return date.year == self.current_year()
        return False

    def current_month(self):
        from datetime import datetime
        return datetime.now().month

    def current_year(self):
        from datetime import datetime
        return datetime.now().year

